from __future__ import annotations
import atexit
import os
from pathlib import Path
import signal
import termios
from typing import TYPE_CHECKING
from typing_extensions import Self

if TYPE_CHECKING:
    from auto_iree.config import Config, LLVMConfig
    from auto_iree.device import Device

from auto_iree.config import load_config
from auto_iree.target import Target

class Context():
    # class variable
    _singleton_instance = None

    # instance variable type hint
    _root_dir_abs : Path
    _model_path_abs : Path
    _working_dir_abs : Path
    _config : Config
    _riscv_tool_dir_abs  : Path
    _within : bool
    _initialized : bool

    def __new__(cls, *args, **kwargs) -> Self:
        if cls._singleton_instance is None:
            cls._singleton_instance = super().__new__(cls)
        return cls._singleton_instance

    def __init__(self) -> None:
        self._within = False
        self._initialized = False
        self._tty_device = "/dev/tty"
        self._tty_fd = None
        self._tty_saved = None

    def lazy_init(self, model_path: Path | str, config_path: Path | str) -> Self:
        self._disable_search_space_reduction: bool = False
        self._root_dir_abs = Path(__file__).resolve().parent.parent.parent
        self._model_path_abs = self._root_dir_abs / model_path
        self._working_dir_abs = self._model_path_abs.parent / self._model_path_abs.stem
        self._config = load_config(str(self._root_dir_abs / config_path))
        self._riscv_tool_dir_abs = self.get_build_config().riscv_toolchain.resolve()
        self.device = self.get_target_config().getDevice()
        self._target = self._form_target_from_config(
            self.get_target_config().device, self.get_llvm_config())
        self._initialized = True
        self.device.set_capture() # capture when tuning

        return self

    def _form_target_from_config(self, device_name: str, lc: LLVMConfig):
        tgt_dict = {}
        tgt_dict["device"] = device_name
        tgt_dict["cpu"] = lc.cpu
        tgt_dict["triple"] = lc.triple
        tgt_dict["attr"] = lc.attr.split(",")
        tgt_dict["float_abi"] = "hard"
        tgt_dict["abi"] = "lp64d"
        tgt_dict["vlen"] = lc.vlen
        tgt_dict["tool"] = "iree.3.1.0-llvm.19.0.0" # TODO: better src
        return Target(tgt_dict)


    def __enter__(self) -> Self:
        if not self.isInitialized():
            raise RuntimeError("Context not initialize yet, use lazy_init() first")

        if self._within:
            raise RuntimeError("Already with this context")
        self._within = True

        try:
            self._tty_fd = os.open(self._tty_device, os.O_RDWR | os.O_NOCTTY)
            self._tty_saved = termios.tcgetattr(self._tty_fd)
        except OSError:
            self._tty_fd = None
            self._tty_saved = None

        atexit.register(self._restore_tty_close_fd) # noraml exit
        for s in (signal.SIGINT, signal.SIGTERM, signal.SIGHUP, signal.SIGQUIT):
            signal.signal(s, self._on_signal)

        # working dir create and chdir
        # example:
        # foo/bar/model.mlir -> foo/bar/model/
        # /home/someone/model_name.valid_text.mlir -> /home/someone/model_name.valid_text/
        self._cwd = os.getcwd()
        self._working_dir_abs.mkdir(exist_ok=True)
        os.chdir(self._working_dir_abs)
        return self

    def __exit__(self, exc_type, exc_value, traceback):
        os.chdir(self._cwd)
        self._within = False
        self._restore_tty_close_fd()

    def _restore_tty_close_fd(self):
        if self._tty_fd is None:
            return
        if self._tty_saved is None:
            return

        termios.tcsetattr(self._tty_fd, termios.TCSADRAIN, self._tty_saved)
        self._tty_saved = None
        os.close(self._tty_fd)
        self._tty_fd = None

    def _on_signal(self, sig, _frm):
        self._restore_tty_close_fd()
        os._exit(128 + sig)

    def isInitialized(self):
        return self._initialized

    # config
    def get_llvm_config(self):
        return self._config.build.llvm

    def get_target_config(self):
        return self._config.target

    def get_build_config(self):
        return self._config.build

    # tool
    def get_gdb(self):
        # TODO: gdb might have different name for linux
        return Path(self._config.build.riscv_toolchain) / 'riscv64-elf-gdb'

    def get_iree_compiler(self):
        return self._root_dir_abs / 'third-party' /\
                'iree-install' / 'bin' / "iree-compile"

    def get_ld_lld(self):
        return self._riscv_tool_dir_abs / 'ld.lld'

    def get_clang(self):
        return self._riscv_tool_dir_abs / 'clang'

    def get_clang_cc(self):
        return self._riscv_tool_dir_abs / 'clang++'

    def get_strip(self):
        return self._riscv_tool_dir_abs / 'riscv64-elf-strip'

    def get_iree_riscv_build_dir(self):
        return self.get_thirdparty_dir() / 'iree-build-riscv'

    def get_iree_riscv_runtime_lib_dir(self):
        return self.get_thirdparty_dir() / 'iree-riscv-runtime'

    def get_iree_riscv_runtime_src_dir(self):
        return self.get_thirdparty_dir() / 'iree-src/runtime/src'

    def get_link_script_ae350(self):
        return self._root_dir_abs / "utility/ae350-NN-xip_x.ld"

    def get_root_dir(self):
        return self._root_dir_abs

    def get_entry_src_dir(self):
        return self._root_dir_abs / "src"

    def get_thirdparty_dir(self):
        return self._root_dir_abs / "third-party"

    def get_relpath_to_workdir(self, p: Path):
        return p.relative_to(
            self._working_dir_abs.relative_to(self._root_dir_abs))

    # model
    def get_model_path_abs(self):
        return self._model_path_abs

    def get_working_dir(self):
        return self._working_dir_abs

    # misc
    @property
    def disable_search_space_reduction(self):
        return self._disable_search_space_reduction

    @disable_search_space_reduction.setter
    def disable_search_space_reduction(self, v: bool):
        self._disable_search_space_reduction = v


    def get_target(self):
        return self._target

    def get_device(self) -> Device:
        return self.device

singleton_context = Context()


def getProfileJSONFileName(option_with_transform: bool, option_by_category: bool):

    # option_with_transform and option_with_category coundn't be true at the same time
    if option_with_transform and option_by_category:
        raise RuntimeError(
            "option_with_transform and option_with_category coundn't be true at the same time")

    # option_with_transform is true return "profile_all_with_transform.json"
    if option_with_transform:
        return "profile_all_with_transform.json"

    if option_by_category:
        return "profile_category.json"
        #return "profile_by_category.json"

    return "profile_all.json"


def get_model_artifact_dirs():
    files = ["record", "benchmarks", "OUTPUT", "temp",
             "transform_library", "search_best", "best", "failed_transform"]
    return files
